class Solution:
    def combinationSum2(self, candidates: List[int], target: int) -> List[List[int]]:
        candidates.sort()
        n = len(candidates)
        ans = []
        path = []
        def dfs(idx, remaining):
            if remaining == 0:
                ans.append(path[:])
                return
            for i in range(idx, n):
                c = candidates[i]
                if c > remaining:
                    break
                if i > idx and candidates[i] == candidates[i-1]:
                    continue
                path.append(c)
                dfs(i + 1, remaining - c)
                path.pop()
        dfs(0, target)
        return ans
```

