class Solution:
    def findEvenNumbers(self, digits: List[int]) -> List[int]:
        ans = []
        counter = [0] * 10
        for d in digits:
            counter[d] += 1
        for i in range(100, 1000, 2):
            d0 = i % 10
            d1 = (i // 10) % 10
            d2 = i // 100
            if d0 == d1:
                if d1 == d2:
                    if counter[d0] < 3:
                        continue
                else:
                    if counter[d0] < 2 or counter[d2] < 1:
                        continue
            elif d0 == d2:
                if counter[d0] < 2 or counter[d1] < 1:
                    continue
            elif d1 == d2:
                if counter[d1] < 2 or counter[d0] < 1:
                    continue
            else:
                if counter[d0] < 1 or counter[d1] < 1 or counter[d2] < 1:
                    continue
            ans.append(i)
        return ans
